                          }`}
                      >
                          {letter}
                      </motion.span>
                  ))}
              </span>
          ))}
        </h1>

        <motion.p 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 1, duration: 1 }}
          className="text-lg md:text-xl text-brand-gray/60 max-w-2xl font-light leading-relaxed mb-12"
        >
