        </motion.p>

        {/* CTA Buttons */}
        <motion.div 
           initial={{ opacity: 0, y: 20 }}
           animate={{ opacity: 1, y: 0 }}
           transition={{ delay: 1.2, duration: 1 }}
           className="flex flex-col sm:flex-row gap-4 w-full justify-center"
        >
          <a 
