import React, { useState, useEffect, useRef, Suspense } from 'react';

interface SectionLoaderProps {
  children: React.ReactNode;
  id?: string;
  className?: string;
  minHeight?: string;
}

const SectionLoader: React.FC<SectionLoaderProps> = ({ 
  children, 
  id, 
  className = "", 
  minHeight = "600px" 
}) => {
  const [isVisible, setIsVisible] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true);
          observer.disconnect();
        }
      },
      { 
        // Start loading when the user is 200px away from the section
        rootMargin: '200px', 
        threshold: 0
      }
    );

    if (ref.current) {
      observer.observe(ref.current);
    }

    return () => observer.disconnect();
  }, []);

  return (
    <div 
      ref={ref} 
      id={id} 
      className={`w-full ${className}`}
      style={{ minHeight: !isVisible ? minHeight : undefined }}
    >
      {isVisible ? (
        <Suspense fallback={
          <div className="w-full h-full flex items-center justify-center text-brand-cyan/20 animate-pulse" style={{ minHeight }}>
            Loading...
          </div>
        }>
          {children}
        </Suspense>
      ) : null}
    </div>
  );
};

export default SectionLoader;

